# Extraction eval: precision and recall on JSON output
import json

def score_extraction(golden: dict, predicted: str) -> dict:
    """
    golden: the reference extraction result, e.g.
            {'party_a': 'Acme Corp', 'effective_date': '2025-01-01', 'value_usd': 500000}
    predicted: the model's raw text output (expected to be JSON)
    """
    try:
        pred = json.loads(predicted)
    except json.JSONDecodeError:
        return {"precision": 0.0, "recall": 0.0, "f1": 0.0, "parse_error": True}

    # Count matches (exact string match after lowercase + strip)
    def norm(v): return str(v).lower().strip() if v is not None else ""

    true_pos = sum(
        1 for k, v in golden.items()
        if k in pred and norm(pred[k]) == norm(v)
    )
    precision = true_pos / len(pred) if pred else 0.0
    recall = true_pos / len(golden) if golden else 0.0
    f1 = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0.0

    return {"precision": round(precision, 3), "recall": round(recall, 3), "f1": round(f1, 3)}

# Example:
# golden = {"party_a": "Acme Corp", "effective_date": "2025-01-01", "value_usd": "500000"}
# model_output = '{"party_a": "Acme Corp", "effective_date": "2025-01-01", "value_usd": "500000"}'
