# Classification eval with per-class accuracy and macro F1
from collections import defaultdict

def score_classification(golden_labels: list[str], predicted_labels: list[str]) -> dict:
    assert len(golden_labels) == len(predicted_labels)
    classes = sorted(set(golden_labels))

    # Per-class precision and recall
    tp = defaultdict(int); fp = defaultdict(int); fn = defaultdict(int)
    for gold, pred in zip(golden_labels, predicted_labels):
        if gold == pred:
            tp[gold] += 1
        else:
            fp[pred] += 1
            fn[gold] += 1

    per_class = {}
    for c in classes:
        p = tp[c] / (tp[c] + fp[c]) if (tp[c] + fp[c]) > 0 else 0.0
        r = tp[c] / (tp[c] + fn[c]) if (tp[c] + fn[c]) > 0 else 0.0
        f1 = 2 * p * r / (p + r) if (p + r) > 0 else 0.0
        per_class[c] = {"precision": round(p, 3), "recall": round(r, 3), "f1": round(f1, 3)}

    overall_accuracy = sum(g == p for g, p in zip(golden_labels, predicted_labels)) / len(golden_labels)
    macro_f1 = sum(v["f1"] for v in per_class.values()) / len(classes)

    return {
        "accuracy": round(overall_accuracy, 3),
        "macro_f1": round(macro_f1, 3),
        "per_class": per_class,
    }
